  # The serial ports (Msvm_SerialPortSettingData) already exist as child RASDs of the VSSD
  $vssd2=$vm.GetRelated('Msvm_VirtualSystemSettingData') | Select-Object -First 1
  $serials=@(([wmi]$vssd2.__PATH).GetRelated('Msvm_SerialPortSettingData'))
  # Select COM 1, set Connection(string[]) to the named pipe path, then ModifyResourceSettings
