  $vssd3=$vm.GetRelated('Msvm_VirtualSystemSettingData') | Select-Object -First 1
  $com2=@(([wmi]$vssd3.__PATH).GetRelated('Msvm_SerialPortSettingData')) | Where-Object { $_.InstanceID -eq $com.InstanceID } | Select-Object -First 1
